mapper.select:
select order_id, request_id, user_id, amount, status, payee_account, failure_reason, create_time, update_time
from withdraw_order
where request_id = #{requestId}

select order_id, request_id, user_id, amount, status, payee_account, failure_reason, create_time, update_time
from withdraw_order
where user_id = #{userId, jdbcType=BINARY}
  and request_id = #{requestId}

mapper.update:
update withdraw_order
set status = #{toStatus},
    update_time = current_timestamp
where user_id = #{userId, jdbcType=BINARY}
  and request_id = #{requestId}
  and status = #{fromStatus}
